#!/bin/bash
# Population Genetics for Conservation -- One-Shot Installer
# Run: bash install_popgen.sh
# Creates ~/population_genetics/ with all files ready to push
set -e
REPO="$HOME/population_genetics"
echo "Creating repository at $REPO"
mkdir -p "$REPO/assets/css" "$REPO/assets/js" "$REPO/assets/images"
cd "$REPO"
echo "Directories created"

echo "Writing source files..."

# --- index.html ---
echo "  index.html"
echo "" | base64 -d > "$REPO/index.html"

# --- assets/css/style.css ---
echo "  assets/css/style.css"
echo "" | base64 -d > "$REPO/assets/css/style.css"

# --- assets/js/main.js ---
echo "  assets/js/main.js"
echo "" | base64 -d > "$REPO/assets/js/main.js"

# --- README.md ---
echo "  README.md"
echo "" | base64 -d > "$REPO/README.md"

# --- assets/images/01_depth_coverage.png ---
echo "  assets/images/01_depth_coverage.png"
echo "" | base64 -d > "$REPO/assets/images/01_depth_coverage.png"

# --- assets/images/02_kenya_parks_map.png ---
echo "  assets/images/02_kenya_parks_map.png"
echo "" | base64 -d > "$REPO/assets/images/02_kenya_parks_map.png"

# --- assets/images/03_shell_directory.png ---
echo "  assets/images/03_shell_directory.png"
echo "" | base64 -d > "$REPO/assets/images/03_shell_directory.png"

# --- assets/images/04_fastq_explainer.png ---
echo "  assets/images/04_fastq_explainer.png"
echo "" | base64 -d > "$REPO/assets/images/04_fastq_explainer.png"

# --- assets/images/05_hardy_weinberg.png ---
echo "  assets/images/05_hardy_weinberg.png"
echo "" | base64 -d > "$REPO/assets/images/05_hardy_weinberg.png"

# --- assets/images/06_population_structure.png ---
echo "  assets/images/06_population_structure.png"
echo "" | base64 -d > "$REPO/assets/images/06_population_structure.png"

# --- assets/images/07_diversity_ho_he_pi.png ---
echo "  assets/images/07_diversity_ho_he_pi.png"
echo "" | base64 -d > "$REPO/assets/images/07_diversity_ho_he_pi.png"

# --- assets/images/08_fst_structure.png ---
echo "  assets/images/08_fst_structure.png"
echo "" | base64 -d > "$REPO/assets/images/08_fst_structure.png"

# --- assets/images/09_selection_types.png ---
echo "  assets/images/09_selection_types.png"
echo "" | base64 -d > "$REPO/assets/images/09_selection_types.png"

# --- assets/images/10_pipeline_workflow.png ---
echo "  assets/images/10_pipeline_workflow.png"
echo "" | base64 -d > "$REPO/assets/images/10_pipeline_workflow.png"

# --- assets/images/11_tajimas_d.png ---
echo "  assets/images/11_tajimas_d.png"
echo "" | base64 -d > "$REPO/assets/images/11_tajimas_d.png"

echo "All files written."

cd "$REPO"

echo ""
echo "Initialising git repository..."
git init
git add .
git commit -m "Population genetics for conservation: interactive training material

Modules covering sequencing strategy, the shell and FASTQ files,
quality control, read mapping, variant calling and filtering,
Hardy-Weinberg equilibrium and population structure, genetic
diversity (Ho, He, pi), demographic history, and selection and
genetic load. Includes discussion questions with answer panels,
case studies labelled as documented or hypothetical, a real Kenya
boundary map for geographic orientation, and a full bibliography.

Core reference: Hedrick, Genetics of Populations, 4th edition."

echo ""
echo "Adding remote and pushing..."
git branch -M main
git remote add origin https://github.com/Rodneyomukuti/population_genetics.git
git push -u origin main

echo ""
echo "============================================================"
echo "Done. Repository pushed to GitHub."
echo ""
echo "To enable GitHub Pages:"
echo "  1. https://github.com/Rodneyomukuti/population_genetics/settings/pages"
echo "  2. Source: Deploy from a branch -> main -> / (root) -> Save"
echo "  3. Site will be live in about 60 seconds at:"
echo "     https://Rodneyomukuti.github.io/population_genetics"
echo "============================================================"
